            client.relay_last_probe_ns = monotonicNs();
            var detail: [192]u8 = undefined;
            const msg = std.fmt.bufPrint(&detail, "client_id={d} id={d} kind={s} pending_left={d}", .{ client.client_id, request.request_id, @tagName(request.kind), client.pending_probe_requests.items.len }) catch "";
