        const signal_cb = event_loop_mod.TimerCallback{
            .context = @ptrCast(self),
            .func = @ptrCast(&struct {
                fn check(ctx: *anyopaque) void {
                    const server: *Server = @ptrCast(@alignCast(ctx));
